import logging
from services.common.Helpers.DatabaseConnector import DatabaseConnector
REQUIRED_TABLES = ['downloads_soundcloud_accounts', 'downloads_soundcloud_archive', 'downloads_youtube_accounts', 'downloads_youtube_archive', 'library_artists', 'rules_artist_genre', 'rules_catid_label', 'rules_festival_data', 'rules_genres', 'rules_ignored_artists', 'rules_ignored_genres', 'rules_label_genre', 'rules_subgenre_hierarchy', 'rules_genre_backlog']

def ensure_tables_exist() -> None:
    """Ensure required database tables exist."""
    table_queries = {'downloads_soundcloud_accounts': '\n            CREATE TABLE IF NOT EXISTS downloads_soundcloud_accounts (\n                name VARCHAR(255),\n                soundcloud_id VARCHAR(255),\n                PRIMARY KEY (name)\n            )\n        ', 'downloads_soundcloud_archive': '\n            CREATE TABLE IF NOT EXISTS downloads_soundcloud_archive (\n                id INT AUTO_INCREMENT PRIMARY KEY,\n                account VARCHAR(255),\n                video_id VARCHAR(255),\n                filename TEXT,\n                url TEXT,\n                title TEXT,\n                added_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n                INDEX(account),\n                INDEX(video_id)\n            )\n        ', 'downloads_youtube_accounts': '\n            CREATE TABLE IF NOT EXISTS downloads_youtube_accounts (\n                name VARCHAR(255) PRIMARY KEY\n            )\n        ', 'downloads_youtube_archive': '\n            CREATE TABLE IF NOT EXISTS downloads_youtube_archive (\n                id INT AUTO_INCREMENT PRIMARY KEY,\n                account VARCHAR(255),\n                video_id VARCHAR(255),\n                filename TEXT,\n                url TEXT,\n                title TEXT,\n                added_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n                INDEX(account),\n                INDEX(video_id)\n            )\n        ', 'library_artists': '\n            CREATE TABLE IF NOT EXISTS library_artists (\n                id INT AUTO_INCREMENT PRIMARY KEY,\n                name VARCHAR(255) NOT NULL,\n                INDEX(name)\n            )\n        ', 'rules_artist_genre': '\n            CREATE TABLE IF NOT EXISTS rules_artist_genre (\n                artist VARCHAR(255) NOT NULL,\n                genre VARCHAR(255) NOT NULL,\n                PRIMARY KEY (artist, genre)\n            )\n        ', 'rules_catid_label': '\n            CREATE TABLE IF NOT EXISTS rules_catid_label (\n                catid VARCHAR(255) PRIMARY KEY,\n                label VARCHAR(255) NOT NULL\n            )\n        ', 'rules_festival_data': '\n            CREATE TABLE IF NOT EXISTS rules_festival_data (\n                festival VARCHAR(255) NOT NULL,\n                year INT NOT NULL,\n                date DATE NOT NULL,\n                PRIMARY KEY (festival, year)\n            )\n        ', 'rules_genres': '\n            CREATE TABLE IF NOT EXISTS rules_genres (\n                id INT AUTO_INCREMENT PRIMARY KEY,\n                name VARCHAR(100) NOT NULL UNIQUE,\n                corrected_genre VARCHAR(255)\n            )\n        ', 'rules_ignored_artists': '\n            CREATE TABLE IF NOT EXISTS rules_ignored_artists (\n                id INT AUTO_INCREMENT PRIMARY KEY,\n                name VARCHAR(255) NOT NULL,\n                corrected_name VARCHAR(255),\n                INDEX(name)\n            )\n        ', 'rules_ignored_genres': '\n            CREATE TABLE IF NOT EXISTS rules_ignored_genres (\n                name VARCHAR(255) PRIMARY KEY\n            )\n        ', 'rules_label_genre': '\n            CREATE TABLE IF NOT EXISTS rules_label_genre (\n                label VARCHAR(255) NOT NULL,\n                genre VARCHAR(255) NOT NULL,\n                PRIMARY KEY (label, genre)\n            )\n        ', 'rules_subgenre_hierarchy': '\n            CREATE TABLE IF NOT EXISTS rules_subgenre_hierarchy (\n                subgenre VARCHAR(255) NOT NULL,\n                genre VARCHAR(255) NOT NULL,\n                PRIMARY KEY (subgenre, genre)\n            )\n        ', 'rules_genre_backlog': '\n            CREATE TABLE IF NOT EXISTS rules_genre_backlog (\n                id INT AUTO_INCREMENT PRIMARY KEY,\n                genre VARCHAR(255) UNIQUE,\n                detected_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n            )\n        '}
    queries = [table_queries[table] for table in REQUIRED_TABLES]
    try:
        conn = DatabaseConnector().connect()
        try:
            with conn.cursor() as cursor:
                for query in queries:
                    print(query)
                    cursor.execute(query)
            conn.commit()
        finally:
            conn.close()
    except Exception as exc:
        logging.warning('Failed to ensure DB tables exist: %s', exc)